import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.B9unkguw.js";const p=JSON.parse(`{"title":"What's New","description":"","frontmatter":{},"headers":[],"relativePath":"tr/qgc-user-guide/getting_started/whats_new.md","filePath":"tr/qgc-user-guide/getting_started/whats_new.md"}`),n={name:"tr/qgc-user-guide/getting_started/whats_new.md"};function r(l,e,s,d,h,c){return t(),i("div",null,e[0]||(e[0]=[o('<h1 id="what-s-new" tabindex="-1">What&#39;s New <a class="header-anchor" href="#what-s-new" aria-label="Permalink to &quot;What&#39;s New&quot;">​</a></h1><p>This page highlights user-facing changes since the last stable release (V5.0).</p><h2 id="fly-view" tabindex="-1">Fly View <a class="header-anchor" href="#fly-view" aria-label="Permalink to &quot;Fly View&quot;">​</a></h2><h3 id="toolbar-improvements" tabindex="-1">Toolbar Improvements <a class="header-anchor" href="#toolbar-improvements" aria-label="Permalink to &quot;Toolbar Improvements&quot;">​</a></h3><ul><li>Individual toolbar dropdowns can now be expanded to show app/vehicle settings useful during flight, reducing the need to navigate to Vehicle Configuration or Application Settings between flights.</li><li><strong>Flight Modes</strong>: Configurable list allows you to remove unused flight modes from the toolbar.</li><li><strong>Battery</strong>: Dynamic bars with configurable thresholds (100%, Config 1, Config 2, Low, Critical).</li><li>The <strong>GPS/RTK GPS</strong> indicator now shows RTK correction link status even when no vehicle is connected, making it easier to verify RTK base station reception before flight. A separate <strong>GPS Resilience</strong> indicator appears when the vehicle reports GPS spoofing or jamming state, with per-GPS details in the dropdown.</li></ul><h3 id="instrument-selection" tabindex="-1">Instrument Selection <a class="header-anchor" href="#instrument-selection" aria-label="Permalink to &quot;Instrument Selection&quot;">​</a></h3><p>Right-click on desktop or long-press on mobile to switch between different instrument clusters.</p><h3 id="camera-ui-rework" tabindex="-1">Camera UI Rework <a class="header-anchor" href="#camera-ui-rework" aria-label="Permalink to &quot;Camera UI Rework&quot;">​</a></h3><p>The camera management code and UI have been significantly reworked. The camera UI now correctly respects camera capability flags and modes, and behavior is more consistent across different camera types and configurations.</p><h3 id="guided-mode-and-multi-vehicle" tabindex="-1">Guided Mode and Multi-Vehicle <a class="header-anchor" href="#guided-mode-and-multi-vehicle" aria-label="Permalink to &quot;Guided Mode and Multi-Vehicle&quot;">​</a></h3><ul><li>Better support for Guided GoTo Location, Orbit, and Fixed Wing Loiter.</li><li>Multi-vehicle support improvements: configurable telemetry display and better support for applying actions to all vehicles.</li></ul><h2 id="plan-view" tabindex="-1">Plan View <a class="header-anchor" href="#plan-view" aria-label="Permalink to &quot;Plan View&quot;">​</a></h2><h3 id="toolbar-rework" tabindex="-1">Toolbar Rework <a class="header-anchor" href="#toolbar-rework" aria-label="Permalink to &quot;Toolbar Rework&quot;">​</a></h3><p>The Plan View toolbar has been completely reworked:</p><ul><li>Explicit <strong>Open</strong>, <strong>Save</strong>, <strong>Upload</strong>, and <strong>Clear</strong> buttons replace the old File tool button.</li><li>Vehicle upload and storage status are shown directly in the toolbar.</li><li><strong>Save</strong> and <strong>Upload</strong> buttons are highlighted when there are unsaved or un-uploaded changes.</li><li>A hamburger menu (☰) provides additional options such as Save as KML and Download from vehicle.</li><li>Plan creation from a template has moved to the right panel and is shown only when the plan is empty.</li></ul><h3 id="mission-status-panel" tabindex="-1">Mission Status Panel <a class="header-anchor" href="#mission-status-panel" aria-label="Permalink to &quot;Mission Status Panel&quot;">​</a></h3><p>A new collapsible <strong>Mission Status</strong> panel at the bottom of the Plan View shows terrain profile and mission statistics (distance, time, maximum altitude). Switchable sub-panels let you toggle between terrain data and mission stats.</p><h3 id="click-to-set-home-position" tabindex="-1">Click-to-Set Home Position <a class="header-anchor" href="#click-to-set-home-position" aria-label="Permalink to &quot;Click-to-Set Home Position&quot;">​</a></h3><p>The home position in Plan View is now set by an explicit first click on the map rather than tracking the map center. Mission editing tools (Takeoff, Waypoint, Pattern, Land, ROI) are disabled until the home position is placed, preventing accidentally placing items before the reference point is defined.</p><h3 id="plan-templates-with-vehicle-class-filtering" tabindex="-1">Plan Templates with Vehicle Class Filtering <a class="header-anchor" href="#plan-templates-with-vehicle-class-filtering" aria-label="Permalink to &quot;Plan Templates with Vehicle Class Filtering&quot;">​</a></h3><p>The Plan Creator now filters available plan templates by vehicle class (multirotor, fixed wing, VTOL, rover, sub), showing only templates compatible with the connected or configured vehicle.</p><h3 id="multiple-fixed-wing-landing-sequences" tabindex="-1">Multiple Fixed Wing Landing Sequences <a class="header-anchor" href="#multiple-fixed-wing-landing-sequences" aria-label="Permalink to &quot;Multiple Fixed Wing Landing Sequences&quot;">​</a></h3><p>Multiple fixed wing landing sequences can now be planned for landings at different locations.</p><h2 id="vehicle-configuration" tabindex="-1">Vehicle Configuration <a class="header-anchor" href="#vehicle-configuration" aria-label="Permalink to &quot;Vehicle Configuration&quot;">​</a></h2><p>Vehicle Configuration has been renamed from Vehicle Setup and is now intended mainly for initial vehicle design and configuration, not changes between flights.</p><h3 id="parameter-editor-—-mission-planner-file-import" tabindex="-1">Parameter Editor — Mission Planner File Import <a class="header-anchor" href="#parameter-editor-—-mission-planner-file-import" aria-label="Permalink to &quot;Parameter Editor — Mission Planner File Import&quot;">​</a></h3><p>The parameter diff dialog can now load Mission Planner <code>.param</code> files (whitespace-separated 5-column format) in addition to the existing QGC <code>.params</code> format. Select a <code>.param</code> file using the new <strong>Mission Planner Files (*.param)</strong> filter in the load dialog; differences from the vehicle&#39;s current values are shown as usual before any changes are applied.</p><h3 id="ardupilot-—-servo-outputs" tabindex="-1">ArduPilot — Servo Outputs <a class="header-anchor" href="#ardupilot-—-servo-outputs" aria-label="Permalink to &quot;ArduPilot — Servo Outputs&quot;">​</a></h3><p>A new <strong>Servo Outputs</strong> page provides real-time visualization and configuration of servo outputs for ArduPilot vehicles:</p><ul><li>Live PWM output bars updated in real time.</li><li>Per-channel function assignment, direction reversal, and min/max/trim PWM editing.</li></ul><h3 id="ardupilot-—-scripting" tabindex="-1">ArduPilot — Scripting <a class="header-anchor" href="#ardupilot-—-scripting" aria-label="Permalink to &quot;ArduPilot — Scripting&quot;">​</a></h3><p>A new <strong>Scripting</strong> page lets you manage Lua scripts on ArduPilot vehicles directly from QGroundControl:</p><ul><li>Browse, upload, and delete scripts stored on the vehicle via MAVLink FTP.</li><li>No need for a separate file manager or SD card access.</li></ul><h3 id="ardupilot-—-safety-failsafe-modernization" tabindex="-1">ArduPilot — Safety Failsafe Modernization <a class="header-anchor" href="#ardupilot-—-safety-failsafe-modernization" aria-label="Permalink to &quot;ArduPilot — Safety Failsafe Modernization&quot;">​</a></h3><p>The ArduPilot Safety setup page has been modernized with vehicle-specific failsafe sections for Copter, Plane, and Rover. Controls use consistent slider and radio-button patterns, and a new <code>FactBitMaskCheckBoxSlider</code> control makes bitmask parameters much easier to configure.</p><h3 id="ardupilot-—-logging-configuration" tabindex="-1">ArduPilot — Logging Configuration <a class="header-anchor" href="#ardupilot-—-logging-configuration" aria-label="Permalink to &quot;ArduPilot — Logging Configuration&quot;">​</a></h3><p>A new <strong>Logging</strong> page lets you configure ArduPilot logging parameters directly from QGroundControl, including storage backends (<code>LOG_BACKEND_TYPE</code>), data group bitmasks (<code>LOG_BITMASK</code>), rate limits, and disarmed logging options.</p><h3 id="joystick-—-manual-control-extensions" tabindex="-1">Joystick — Manual Control Extensions <a class="header-anchor" href="#joystick-—-manual-control-extensions" aria-label="Permalink to &quot;Joystick — Manual Control Extensions&quot;">​</a></h3><p>Full support for MAVLink manual control extensions has been added to the Joystick configuration:</p><ul><li>Improved settings read/write with validation.</li><li>Improved logging.</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Joystick settings from earlier versions are not migrated; joysticks will need to be re-calibrated and re-enabled after updating.</p></div><h2 id="application-settings" tabindex="-1">Application Settings <a class="header-anchor" href="#application-settings" aria-label="Permalink to &quot;Application Settings&quot;">​</a></h2><h3 id="searchable-settings-and-vehicle-config" tabindex="-1">Searchable Settings and Vehicle Config <a class="header-anchor" href="#searchable-settings-and-vehicle-config" aria-label="Permalink to &quot;Searchable Settings and Vehicle Config&quot;">​</a></h3><p>Both the Application Settings pages and the Vehicle Config sidebar now have a <strong>keyword search</strong> field. Typing a word filters the visible sections across all pages, making it much faster to find a specific setting without knowing which page it lives on.</p><h3 id="json-driven-settings-ui" tabindex="-1">JSON-Driven Settings UI <a class="header-anchor" href="#json-driven-settings-ui" aria-label="Permalink to &quot;JSON-Driven Settings UI&quot;">​</a></h3><p>All Application Settings pages are now generated from JSON metadata rather than hand-coded QML. Settings are organized into collapsible sections with consistent layout.</p><h3 id="mavlink-actions" tabindex="-1">MAVLink Actions <a class="header-anchor" href="#mavlink-actions" aria-label="Permalink to &quot;MAVLink Actions&quot;">​</a></h3><p>New and updated MAVLink Actions support in Fly View settings.</p><h3 id="virtual-joystick" tabindex="-1">Virtual Joystick <a class="header-anchor" href="#virtual-joystick" aria-label="Permalink to &quot;Virtual Joystick&quot;">​</a></h3><p>Virtual Joystick now supports left-handed mode.</p><h3 id="ntrip-rtk-correction-link" tabindex="-1">NTRIP RTK Correction Link <a class="header-anchor" href="#ntrip-rtk-correction-link" aria-label="Permalink to &quot;NTRIP RTK Correction Link&quot;">​</a></h3><p>QGroundControl now includes a built-in NTRIP client for streaming RTK correction data to the vehicle. Configure the NTRIP server, mount point, and credentials in Application Settings; QGroundControl connects and forwards corrections automatically.</p><h3 id="mavlink-2-message-signing" tabindex="-1">MAVLink 2 Message Signing <a class="header-anchor" href="#mavlink-2-message-signing" aria-label="Permalink to &quot;MAVLink 2 Message Signing&quot;">​</a></h3><p>The Telemetry settings page now includes a <strong>MAVLink 2 Signing</strong> section. Signing cryptographically authenticates all messages between QGroundControl and the vehicle, preventing unauthorized command injection. Keys are created by entering a friendly name and passphrase; only the SHA-256 hash is stored.</p><h3 id="configurable-stream-rates-ardupilot" tabindex="-1">Configurable Stream Rates (ArduPilot) <a class="header-anchor" href="#configurable-stream-rates-ardupilot" aria-label="Permalink to &quot;Configurable Stream Rates (ArduPilot)&quot;">​</a></h3><p>Configurable telemetry stream rate support for ArduPilot vehicles.</p><h2 id="analysis-logs" tabindex="-1">Analysis &amp; Logs <a class="header-anchor" href="#analysis-logs" aria-label="Permalink to &quot;Analysis &amp; Logs&quot;">​</a></h2><h3 id="log-viewer" tabindex="-1">Log Viewer <a class="header-anchor" href="#log-viewer" aria-label="Permalink to &quot;Log Viewer&quot;">​</a></h3><p>The Log Viewer (<strong>Analyze &gt; Log Viewer</strong>) is a new unified post-flight analysis tool that supports three log formats:</p><ul><li><strong>ArduPilot DataFlash</strong> (<code>.bin</code> / <code>.log</code>) — field charting, GPS flight path map, parameter inspection, and status messages.</li><li><strong>PX4 ULog</strong> (<code>.ulg</code>) — same capabilities using PX4 log format.</li><li><strong>MAVLink Telemetry</strong> (<code>.tlog</code>) — playback with speed control, seek slider, and live MAVLink Inspector.</li></ul><p>The Charting tab lets you select any logged field for time-series plotting with zoom and a value popup showing current, minimum, and maximum values. The Map tab shows the GPS flight path auto-fitted to the screen with an altitude mini-chart below it; clicking or dragging on the altitude chart moves a position marker on the map. The Parameters tab lists all recorded parameters with a &quot;changed only&quot; filter.</p><h3 id="onboard-logs-—-ftp-download" tabindex="-1">Onboard Logs — FTP Download <a class="header-anchor" href="#onboard-logs-—-ftp-download" aria-label="Permalink to &quot;Onboard Logs — FTP Download&quot;">​</a></h3><p>A new <strong>Onboard Logs (FTP)</strong> tab in Analyze View downloads logs from the vehicle using the MAVLink FTP protocol, providing a dedicated FTP path alongside the existing legacy log download method.</p><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><h3 id="touch-screen-ui-updates" tabindex="-1">Touch Screen UI Updates <a class="header-anchor" href="#touch-screen-ui-updates" aria-label="Permalink to &quot;Touch Screen UI Updates&quot;">​</a></h3><p>Focused UI updates for smaller touch screens used by integrated controllers such as Herelink:</p><ul><li>New slider controls for value entry.</li><li>Better touch support for various controls.</li></ul><h3 id="mavlink-v1-removed" tabindex="-1">MAVLink v1 Removed <a class="header-anchor" href="#mavlink-v1-removed" aria-label="Permalink to &quot;MAVLink v1 Removed&quot;">​</a></h3><p>Support for the legacy MAVLink v1 message protocol has been removed. QGroundControl now requires MAVLink v2.</p><h3 id="qt-framework-update" tabindex="-1">Qt Framework Update <a class="header-anchor" href="#qt-framework-update" aria-label="Permalink to &quot;Qt Framework Update&quot;">​</a></h3><p>The Qt framework has been updated from 6.8.3 to 6.10.1, and the charting library has been migrated from the deprecated Qt Charts to the new Qt Graphs module.</p><h3 id="build-system" tabindex="-1">Build System <a class="header-anchor" href="#build-system" aria-label="Permalink to &quot;Build System&quot;">​</a></h3><p>The build system has been fully converted to CMake (qmake is no longer supported). GStreamer support updated to 1.22.</p>',73)]))}const g=a(n,[["render",r]]);export{p as __pageData,g as default};
